1	type Item = { type: string };
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: "quote"; items: Item[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	};
20	
21	export const runScenario = (scenario: Scenario): ScenarioResult => {
22	  const items = scenario.steps[0].items;
23	  const basePremium = items.length === 0 ? 0 : BASE_PREMIUMS[items[0].type];
24	  return {
25	    results: [{ premium: basePremium + basePremium / 10 + PROCESSING_FEE }],
26	  };
27	};
